/**
 * Regenerative Endowment Simulator — core financial math.
 *
 * Pure module: no DOM, no side effects. Fully testable in Node/Vitest.
 *
 * ## Principal-preservation model
 *
 * The fund targets preservation of real (inflation-adjusted) purchasing power.
 * Each year it earns a nominal return, inflates the required principal floor,
 * and distributes a configured fraction of the surplus (the "real yield") to
 * regenerative projects.
 *
 * ### Year-t math (all values in nominal currency units)
 *
 *   gross[t]        = P[t-1] × (1 + r_nominal)
 *   inflation_floor = P[t-1] × (1 + inflation)
 *   distributable   = gross[t] − inflation_floor
 *                   = P[t-1] × (r_nominal − inflation)
 *   distribution    = distributable × dist_rate
 *   P[t]            = gross[t] − distribution
 *                   = inflation_floor + distributable × (1 − dist_rate)
 *
 * Real principal (in year-0 purchasing power):
 *   P_real[t]       = P[t] / (1 + inflation)^t
 *
 * ### Special case: dist_rate = 1.0
 *   distribution    = distributable  (all real yield paid out)
 *   P[t]            = inflation_floor = P[t-1] × (1 + inflation)
 *   P_real[t]       = P_0  (constant)  ← exact principal preservation
 *
 * ### Downside scenario
 *   Same model with r_nominal_low = r_nominal − downsideMargin.
 *   If r_nominal_low < inflation, distributable < 0: principal erodes.
 */
import type { SimulationParams, SimulationResult, YearResult } from "./types.js";

/** Default downside margin (subtract from nominalReturn for pessimistic scenario). */
export const DEFAULT_DOWNSIDE_MARGIN = 0.02;

/**
 * Run the endowment simulation for `params.years` years.
 * Returns year-by-year results starting from year 0 (initial state).
 */
export function runScenario(params: SimulationParams, nominalReturn: number): YearResult[] {
  const { initialPrincipal, inflation, distributionRate, years } = params;

  const results: YearResult[] = [];

  // Year 0: initial state (no distributions yet)
  results.push({
    year: 0,
    nominalPrincipal: initialPrincipal,
    realPrincipal: initialPrincipal, // base year, deflator = 1.0
    distribution: 0,
    cumulativeDistributions: 0,
    distributable: 0,
  });

  let cumulativeDistributions = 0;

  for (let t = 1; t <= years; t++) {
    const prev = results[t - 1];
    const P_prev = prev.nominalPrincipal;

    // Gross fund value after year's returns
    const gross = P_prev * (1 + nominalReturn);

    // Minimum principal needed to preserve real value
    const inflationFloor = P_prev * (1 + inflation);

    // Amount available to distribute (positive = fund earned above inflation)
    const distributable = gross - inflationFloor;

    // Actual distribution (capped at zero — we don't force distribution if fund eroded)
    const distribution = Math.max(0, distributable) * distributionRate;

    // End-of-year nominal principal
    const nominalPrincipal = gross - distribution;

    // Inflation deflator: (1 + inflation)^t relative to year 0
    const deflator = Math.pow(1 + inflation, t);
    const realPrincipal = nominalPrincipal / deflator;

    cumulativeDistributions += distribution;

    results.push({
      year: t,
      nominalPrincipal,
      realPrincipal,
      distribution,
      cumulativeDistributions,
      distributable,
    });
  }

  return results;
}

/**
 * Run both base and downside scenarios and return the combined result.
 */
export function simulate(
  params: SimulationParams,
  downsideMargin: number = DEFAULT_DOWNSIDE_MARGIN,
): SimulationResult {
  return {
    params,
    downsideMargin,
    base: runScenario(params, params.nominalReturn),
    downside: runScenario(params, params.nominalReturn - downsideMargin),
  };
}

/**
 * Compute the real return rate given nominal return and inflation.
 * Uses the exact Fisher equation: r_real = (1 + r_nominal) / (1 + inflation) - 1
 */
export function realReturn(nominalReturn: number, inflation: number): number {
  return (1 + nominalReturn) / (1 + inflation) - 1;
}

/**
 * Format a number as a currency string (no external deps).
 */
export function formatCurrency(value: number, decimals = 0): string {
  return value.toLocaleString("en-US", {
    minimumFractionDigits: decimals,
    maximumFractionDigits: decimals,
  });
}

/**
 * Format a decimal as a percentage string.
 */
export function formatPercent(value: number, decimals = 1): string {
  return (value * 100).toFixed(decimals) + "%";
}
