/**
 * Hand-rolled SVG chart renderer for the endowment simulator.
 *
 * Renders a multi-series line chart showing:
 *   - Base scenario: nominal principal, real principal, cumulative distributions
 *   - Downside scenario: nominal principal (dashed)
 *
 * No external dependencies. Returns an SVG string that can be set as innerHTML.
 */
import type { YearResult } from "./types.js";
import { formatCurrency } from "./simulation.js";

export interface ChartSeries {
  label: string;
  data: number[];
  color: string;
  dashed?: boolean;
  strokeWidth?: number;
}

interface ChartOptions {
  width: number;
  height: number;
  paddingLeft: number;
  paddingRight: number;
  paddingTop: number;
  paddingBottom: number;
  xLabels: string[];
  yLabel: string;
  tickCount: number;
}

const DEFAULT_OPTIONS: ChartOptions = {
  width: 800,
  height: 420,
  paddingLeft: 100,
  paddingRight: 24,
  paddingTop: 32,
  paddingBottom: 56,
  xLabels: [],
  yLabel: "",
  tickCount: 6,
};

function lerp(t: number, min: number, max: number): number {
  return min + (max - min) * t;
}

function dataToSVGPath(
  data: number[],
  dataMin: number,
  dataMax: number,
  opts: ChartOptions,
): string {
  const plotW = opts.width - opts.paddingLeft - opts.paddingRight;
  const plotH = opts.height - opts.paddingTop - opts.paddingBottom;
  const range = dataMax - dataMin || 1;

  return data
    .map((v, i) => {
      const x = opts.paddingLeft + (i / (data.length - 1)) * plotW;
      const y = opts.paddingTop + (1 - (v - dataMin) / range) * plotH;
      return `${i === 0 ? "M" : "L"} ${x.toFixed(2)} ${y.toFixed(2)}`;
    })
    .join(" ");
}

function formatYAxisLabel(value: number): string {
  if (Math.abs(value) >= 1_000_000) {
    return (value / 1_000_000).toFixed(1) + "M";
  }
  if (Math.abs(value) >= 1_000) {
    return (value / 1_000).toFixed(0) + "K";
  }
  return formatCurrency(value);
}

/**
 * Render a line chart as an SVG string.
 */
export function renderLineChart(series: ChartSeries[], options: Partial<ChartOptions> = {}): string {
  const opts: ChartOptions = { ...DEFAULT_OPTIONS, ...options };
  const plotW = opts.width - opts.paddingLeft - opts.paddingRight;
  const plotH = opts.height - opts.paddingTop - opts.paddingBottom;

  // Compute global y-axis extent across all series
  const allValues = series.flatMap((s) => s.data);
  const rawMin = Math.min(...allValues);
  const rawMax = Math.max(...allValues);
  // Add 5% padding above and below
  const range = rawMax - rawMin || 1;
  const yMin = rawMin - range * 0.05;
  const yMax = rawMax + range * 0.05;

  const n = series[0]?.data.length ?? 0;

  // Build axis tick values
  const yTicks: number[] = [];
  for (let i = 0; i <= opts.tickCount; i++) {
    yTicks.push(lerp(i / opts.tickCount, yMin, yMax));
  }

  const svgParts: string[] = [];

  // SVG opening
  svgParts.push(
    `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${opts.width} ${opts.height}" role="img" aria-label="Endowment projection chart">`,
  );

  // Background
  svgParts.push(
    `<rect width="${opts.width}" height="${opts.height}" fill="#0f1117" rx="8"/>`,
  );

  // Plot area background
  svgParts.push(
    `<rect x="${opts.paddingLeft}" y="${opts.paddingTop}" width="${plotW}" height="${plotH}" fill="#161b24" rx="4"/>`,
  );

  // Y-axis gridlines and labels
  for (const tick of yTicks) {
    const y =
      opts.paddingTop +
      (1 - (tick - yMin) / (yMax - yMin)) * plotH;
    svgParts.push(
      `<line x1="${opts.paddingLeft}" y1="${y.toFixed(2)}" x2="${opts.paddingLeft + plotW}" y2="${y.toFixed(2)}" stroke="#2a3045" stroke-width="1"/>`,
    );
    svgParts.push(
      `<text x="${opts.paddingLeft - 8}" y="${(y + 4).toFixed(2)}" text-anchor="end" fill="#7a8299" font-size="11" font-family="system-ui, sans-serif">${formatYAxisLabel(tick)}</text>`,
    );
  }

  // X-axis labels (every year or every N years if crowded)
  const xStep = n > 20 ? 5 : n > 12 ? 2 : 1;
  for (let i = 0; i < n; i++) {
    if (i % xStep !== 0 && i !== n - 1) continue;
    const x = opts.paddingLeft + (i / (n - 1)) * plotW;
    svgParts.push(
      `<text x="${x.toFixed(2)}" y="${opts.paddingTop + plotH + 20}" text-anchor="middle" fill="#7a8299" font-size="11" font-family="system-ui, sans-serif">${opts.xLabels[i] ?? i}</text>`,
    );
  }

  // X-axis label ("Year")
  svgParts.push(
    `<text x="${(opts.paddingLeft + plotW / 2).toFixed(2)}" y="${opts.height - 6}" text-anchor="middle" fill="#4a5568" font-size="12" font-family="system-ui, sans-serif">Year</text>`,
  );

  // Y-axis label
  if (opts.yLabel) {
    svgParts.push(
      `<text x="${14}" y="${(opts.paddingTop + plotH / 2).toFixed(2)}" text-anchor="middle" fill="#4a5568" font-size="12" font-family="system-ui, sans-serif" transform="rotate(-90, 14, ${(opts.paddingTop + plotH / 2).toFixed(2)})">${opts.yLabel}</text>`,
    );
  }

  // Data series paths
  for (const s of series) {
    const d = dataToSVGPath(s.data, yMin, yMax, opts);
    const dashAttr = s.dashed ? ` stroke-dasharray="6 3"` : "";
    const strokeW = s.strokeWidth ?? 2;
    svgParts.push(
      `<path d="${d}" fill="none" stroke="${s.color}" stroke-width="${strokeW}"${dashAttr} stroke-linejoin="round" stroke-linecap="round"/>`,
    );
  }

  // Axes
  svgParts.push(
    `<line x1="${opts.paddingLeft}" y1="${opts.paddingTop}" x2="${opts.paddingLeft}" y2="${opts.paddingTop + plotH}" stroke="#3a4155" stroke-width="1"/>`,
  );
  svgParts.push(
    `<line x1="${opts.paddingLeft}" y1="${opts.paddingTop + plotH}" x2="${opts.paddingLeft + plotW}" y2="${opts.paddingTop + plotH}" stroke="#3a4155" stroke-width="1"/>`,
  );

  // Legend
  const legendY = opts.paddingTop;
  const legendX = opts.paddingLeft + plotW - 20;
  let legendOffset = 0;

  for (const s of series) {
    const lx = legendX - 160;
    const ly = legendY + legendOffset;
    const dashAttr = s.dashed ? ` stroke-dasharray="6 3"` : "";
    svgParts.push(
      `<line x1="${lx}" y1="${ly + 7}" x2="${lx + 24}" y2="${ly + 7}" stroke="${s.color}" stroke-width="${s.strokeWidth ?? 2}"${dashAttr}/>`,
    );
    svgParts.push(
      `<text x="${lx + 30}" y="${ly + 12}" fill="#c8d0e0" font-size="12" font-family="system-ui, sans-serif">${s.label}</text>`,
    );
    legendOffset += 20;
  }

  svgParts.push("</svg>");

  return svgParts.join("\n");
}

/**
 * Build the chart series arrays from base and downside simulation results.
 */
export function buildChartSeries(
  base: YearResult[],
  downside: YearResult[],
): ChartSeries[] {
  return [
    {
      label: "Nominal Principal (base)",
      data: base.map((y) => y.nominalPrincipal),
      color: "#4ade80",
      strokeWidth: 2.5,
    },
    {
      label: "Real Principal (base)",
      data: base.map((y) => y.realPrincipal),
      color: "#60a5fa",
      strokeWidth: 2,
    },
    {
      label: "Cumulative Distributions (base)",
      data: base.map((y) => y.cumulativeDistributions),
      color: "#f59e0b",
      strokeWidth: 2,
    },
    {
      label: "Nominal Principal (downside)",
      data: downside.map((y) => y.nominalPrincipal),
      color: "#f87171",
      strokeWidth: 1.5,
      dashed: true,
    },
    {
      // Downside cumulative distributions are always lower than base when the
      // return is squeezed — this is the key visible divergence between scenarios.
      // At default settings (dist_rate=100%), the nominal-principal lines
      // coincide exactly (both = P*(1+inf)^t); only the distribution series
      // shows the difference.
      label: "Cumul. Distributions (downside)",
      data: downside.map((y) => y.cumulativeDistributions),
      color: "#fb923c",
      strokeWidth: 1.5,
      dashed: true,
    },
  ];
}
