/**
 * Regenerative Endowment Simulator — app entry point.
 *
 * Wires the UI controls → simulation engine → SVG chart renderer.
 * All computation is pure / offline / client-side.
 */
import { simulate, formatCurrency, formatPercent, DEFAULT_DOWNSIDE_MARGIN } from "./simulation.js";
import { buildChartSeries, renderLineChart } from "./chart.js";
import type { SimulationParams } from "./types.js";

// ─── DOM element accessors ────────────────────────────────────────────────────

function getInput(id: string): HTMLInputElement {
  const el = document.getElementById(id);
  if (!(el instanceof HTMLInputElement)) throw new Error(`Input #${id} not found`);
  return el;
}

function getEl(id: string): HTMLElement {
  const el = document.getElementById(id);
  if (!el) throw new Error(`Element #${id} not found`);
  return el;
}

// ─── Read params from form ────────────────────────────────────────────────────

function readParams(): SimulationParams {
  return {
    initialPrincipal: parseFloat(getInput("initial-principal").value) || 1_000_000,
    nominalReturn: parseFloat(getInput("nominal-return").value) / 100,
    inflation: parseFloat(getInput("inflation").value) / 100,
    distributionRate: parseFloat(getInput("distribution-rate").value) / 100,
    years: parseInt(getInput("years").value, 10) || 30,
  };
}

function readDownsideMargin(): number {
  return parseFloat(getInput("downside-margin").value) / 100 || DEFAULT_DOWNSIDE_MARGIN;
}

// ─── Summary stats update ─────────────────────────────────────────────────────

function updateSummary(params: SimulationParams, downsideMargin: number): void {
  const result = simulate(params, downsideMargin);
  const base = result.base;
  const down = result.downside;
  const lastYear = params.years;

  const finalBase = base[lastYear];
  const finalDown = down[lastYear];

  // Base scenario summary
  getEl("stat-final-nominal").textContent = "$" + formatCurrency(finalBase.nominalPrincipal);
  getEl("stat-final-real").textContent = "$" + formatCurrency(finalBase.realPrincipal);
  getEl("stat-cumulative-dist").textContent = "$" + formatCurrency(finalBase.cumulativeDistributions);
  getEl("stat-year1-dist").textContent = "$" + formatCurrency(base[1]?.distribution ?? 0);

  // Real return
  const rReal = (1 + params.nominalReturn) / (1 + params.inflation) - 1;
  getEl("stat-real-return").textContent = formatPercent(rReal);

  // Downside scenario
  getEl("stat-down-final-nominal").textContent = "$" + formatCurrency(finalDown.nominalPrincipal);
  getEl("stat-down-cumulative").textContent = "$" + formatCurrency(finalDown.cumulativeDistributions);
  getEl("stat-down-return").textContent = formatPercent(params.nominalReturn - downsideMargin);

  // Build and render chart.
  // renderLineChart() produces SVG from numeric simulation data only — no user
  // text flows through it.  We parse it with DOMParser (XML mode) rather than
  // setting innerHTML directly so the browser validates it as SVG before
  // insertion, and any accidental markup in a label can never become live HTML.
  const chartContainer = getEl("chart-container");
  const series = buildChartSeries(base, down);
  const xLabels = base.map((y) => String(y.year));
  const svgString = renderLineChart(series, {
    xLabels,
    yLabel: "USD",
    width: Math.max(600, chartContainer.clientWidth || 800),
    height: 380,
  });
  const parser = new DOMParser();
  const svgDoc = parser.parseFromString(svgString, "image/svg+xml");
  const svgEl = svgDoc.documentElement;
  chartContainer.replaceChildren(svgEl);

  // Update table
  updateTable(base, down);
}

// ─── Year-by-year table ───────────────────────────────────────────────────────

/**
 * Populate the results table using safe DOM construction (no innerHTML).
 * All cell content comes from simulation math (numbers → formatted strings),
 * never from raw user input.
 */
function updateTable(
  base: ReturnType<typeof simulate>["base"],
  down: ReturnType<typeof simulate>["downside"],
): void {
  const tbody = document.querySelector<HTMLTableSectionElement>("#results-table tbody");
  if (!tbody) return;

  // Build all rows as a DocumentFragment, then swap in one reflow.
  const fragment = document.createDocumentFragment();

  for (let t = 0; t < base.length; t++) {
    const b = base[t];
    const d = down[t];

    const tr = document.createElement("tr");

    // Helper: append a <td> with textContent
    const cell = (text: string, cls?: string): void => {
      const td = document.createElement("td");
      td.textContent = text;
      if (cls) td.className = cls;
      tr.appendChild(td);
    };

    cell(String(b.year));
    cell("$" + formatCurrency(b.nominalPrincipal));
    cell("$" + formatCurrency(b.realPrincipal));
    cell("$" + formatCurrency(b.distribution));
    cell("$" + formatCurrency(b.cumulativeDistributions));
    cell("$" + formatCurrency(d.nominalPrincipal), "downside");
    cell("$" + formatCurrency(d.distribution), "downside");

    fragment.appendChild(tr);
  }

  tbody.replaceChildren(fragment);
}

// ─── Sync range inputs with number displays ───────────────────────────────────

function syncRangeDisplay(inputId: string, displayId: string, suffix: string): void {
  const input = getInput(inputId);
  const display = getEl(displayId);
  const update = () => { display.textContent = input.value + suffix; };
  input.addEventListener("input", update);
  update();
}

// ─── Bootstrap ───────────────────────────────────────────────────────────────

function run(): void {
  // Wire range displays
  syncRangeDisplay("nominal-return", "nominal-return-display", "%");
  syncRangeDisplay("inflation", "inflation-display", "%");
  syncRangeDisplay("distribution-rate", "distribution-rate-display", "%");
  syncRangeDisplay("downside-margin", "downside-margin-display", "%");
  syncRangeDisplay("years", "years-display", " yr");

  // Format principal input on blur
  const principalInput = getInput("initial-principal");
  principalInput.addEventListener("blur", () => {
    const v = parseFloat(principalInput.value);
    if (!isNaN(v)) principalInput.value = String(v);
  });

  // Re-run simulation on any input change
  const allInputs = document.querySelectorAll("input");
  allInputs.forEach((inp) => {
    inp.addEventListener("input", () => {
      updateSummary(readParams(), readDownsideMargin());
    });
  });

  // Initial render
  updateSummary(readParams(), readDownsideMargin());
}

document.addEventListener("DOMContentLoaded", run);
